    opinion = #{opinion}
where id = #{itemId,jdbcType=INTEGER}

update test_task
inspector=#{inspector}, recorder=#{recorder}, reviewer=#{reviewer}, report_producer=#{reportProducer}, sample_receiving_time=#{sampleReceivingTime}, sample_state_description=#{sampleStateDescription}, sampler=#{sampler}, probationer=#{probationer}, interns=#{interns}, auxiliary_personnel=#{auxiliaryPersonnel},
where id = #{taskId,jdbcType=INTEGER}

