mapper.select:
select count(*) FROM test_task WHERE state =#{state}
and dept_id in
#{id}

SELECT aa.id as sampleId, aa.sample_name as taskSampleName, bb.task_id as taskId FROM test_sample AS aa RIGHT JOIN ( SELECT t1.* FROM test_entrusted_sample_checkitem_rel AS t1 RIGHT JOIN ( SELECT id, entrustment_id FROM test_task WHERE id IN
#{item}
) AS t2 ON t1.entrust_id = t2.entrustment_id ) AS bb ON aa.id = bb.sample_id GROUP BY CONCAT(bb.task_id,aa.id)

SELECT user_id AS inspector, signature_url AS signatureUrl FROM sys_user WHERE user_id IN
#{item}
and signature_url is not null

SELECT t1.id as idItem, t1.check_item_id as checkItemId, t1.task_id as taskId, t1.sample_id as sampleId, t1.state, t1.entrust_id as entrustmentId, t1.check_item_name as checkItemName, t1.edit_data, t1.start_time FROM test_entrusted_sample_checkitem_rel as t1 WHERE 1=1
and t1.id IN
#{id}

SELECT t1.id, t1.sn, t1.alias_name, t1.entrustment_id AS entrustmentId, t1.price, t1.receive_id, t1.required_completion_time AS requiredCompletionTime, t1.task_flow_req AS taskFlowReq, t1.publisher, t1.publish_date AS publishDate, t4.team FROM test_task_pool t1 INNER JOIN ( SELECT tpt.id, tpt.sn, tpt.sample, tpt.entrustment_id AS entrustmentId, tpt.price, tpt.required_completion_time AS requiredCompletionTime, tpt.task_flow_req AS taskFlowReq, tpt.publisher, tpt.receive_id, tpt.publish_date AS publishDate FROM ( SELECT id, sn, entrustment_id, price, required_completion_time, task_flow_req, publisher, publish_date, receive_id, SUBSTRING_INDEX(sample, ',', 1) AS sample, SUBSTRING_INDEX(product_id, ',', 1) AS productId FROM test_task_pool ) AS tpt INNER JOIN ( SELECT t1.technicist_id, t1.product_name, t1.product_id, t3.user_id AS userId FROM test_technicist_capacity t1 LEFT JOIN test_technicist t2 ON t1.technicist_id = t2.id LEFT JOIN sys_user t3 ON t2.user_id = t3.user_id ) t4 ON (tpt.sample = t4.product_name OR tpt.productId = t4.product_id) WHERE t4.userId = #{item.userId} AND tpt.receive_id IS NULL ) t2 ON t1.id = t2.id LEFT JOIN test_entrusted_info t4 ON t1.entrustment_id = t4.id WHERE ( t4.team IN ( SELECT id FROM test_team WHERE pid = #{item.teamId} ) or t4.team = #{item.teamId} OR t4.team IS NULL ) AND t1.receive_id IS NULL AND t1.sample IS NOT NULL
AND t1.sample LIKE CONCAT('%', #{item.sampleName}, '%')
AND t1.publisher LIKE CONCAT('%', #{item.publisher}, '%')
And t1.required_completion_time >=#{item.requireStartTime} and t1.required_completion_time <= #{item.requireEndTime}
And t1.publish_date >=#{item.publishStartTime} and t1.publish_date <= #{item.publishEndTime}
order by t1.id desc

SELECT tb1.id, tb1.sn, tb1.alias_name, tb1.entrustment_id AS entrustmentId, tb1.price, tb1.required_completion_time AS requiredCompletionTime, tb1.task_flow_req AS taskFlowReq, tb1.publisher, tb1.publish_date AS publishDate, tb1.receive_name AS receiveName, tb1.receive_date AS receiveDate, tb1.task_code As taskCode FROM test_task_pool tb1 LEFT JOIN test_task tb2 ON tb1.id = tb2.pool_id WHERE tb1.receive_id= #{item.userId}
AND tb1.sample LIKE CONCAT('%', #{item.sampleName}, '%')
AND tb1.publisher LIKE CONCAT('%', #{item.publisher}, '%')
And tb1.required_completion_time >=#{item.requireStartTime} and tb1.required_completion_time <= #{item.requireEndTime}
And tb1.publish_date >=#{item.publishStartTime} and tb1.publish_date <= #{item.publishEndTime}
And tb1.receive_date >=#{item.receiveStartTime} and tb1.receive_date <= #{item.receiveEndTime}
GROUP BY tb1.id order by tb1.id desc

